        assert_eq!(first_factor_pair(6, 6), Some((1, 6)));
        assert_eq!(first_factor_pair(6, 12), Some((2, 6)));
    }

    #[test]
    fn reports_no_pair() {
        assert_eq!(first_factor_pair(3, 100), None);
    }
}

